  /**
   * Detect content type from user prompt
   */
  detectContentType(prompt) {
    const lowercasePrompt = prompt.toLowerCase();

    // Exclude specific words that should not be detected as news
    if (
      lowercasePrompt.includes("satanda") ||
      lowercasePrompt.includes("buata standar") ||
      lowercasePrompt.includes("buat standar") ||
      lowercasePrompt.includes("standar")
    ) {
      return "general";
    }

    if (
      lowercasePrompt.includes("berita") ||
      lowercasePrompt.includes("artikel") ||
      lowercasePrompt.includes("news")
    ) {
      return "news";
    } else if (
      lowercasePrompt.includes("card") ||
      lowercasePrompt.includes("profil") ||
      lowercasePrompt.includes("produk")
    ) {
      return "card";
    } else if (
      lowercasePrompt.includes("hero") ||
      lowercasePrompt.includes("banner") ||
      lowercasePrompt.includes("header")
    ) {
      return "hero";
    } else if (
      lowercasePrompt.includes("timeline") ||
      lowercasePrompt.includes("step") ||
      lowercasePrompt.includes("proses")
    ) {
      return "timeline";
    } else if (
      lowercasePrompt.includes("statistik") ||
      lowercasePrompt.includes("data") ||
      lowercasePrompt.includes("chart")
    ) {
      return "stats";
    } else if (
      lowercasePrompt.includes("testimoni") ||
      lowercasePrompt.includes("review") ||
      lowercasePrompt.includes("feedback")
    ) {
      return "testimonial";
    } else if (
      lowercasePrompt.includes("galeri") ||
      lowercasePrompt.includes("gallery") ||
      lowercasePrompt.includes("foto")
    ) {
      return "gallery";
    } else if (
      lowercasePrompt.includes("kontak") ||
      lowercasePrompt.includes("contact") ||
      lowercasePrompt.includes("info")
    ) {
      return "contact";
    }

    return "general";
  }

