  /**
   * Update layout information display
   */
  updateLayoutInfo(prompt, layoutInfoGroup, layoutNameEl, layoutDescEl) {
    if (!prompt || prompt.trim().length < 3) {
      layoutInfoGroup.style.display = "none";
      return;
    }

    const contentType = this.detectContentType(prompt);
    const layoutVariations = this.getLayoutVariations(contentType);

    // For news content, default to "Berita Sederhana" (same as News - Simple Layout)
    let randomLayout;
    if (contentType === "news") {
      randomLayout = layoutVariations[0]; // "Berita Sederhana"
    } else {
      randomLayout =
        layoutVariations[Math.floor(Math.random() * layoutVariations.length)];
    }

    this.currentContentType = contentType;
    this.currentLayoutSelection = randomLayout;

    layoutNameEl.textContent = randomLayout.name;
    layoutDescEl.textContent = randomLayout.description;
    layoutInfoGroup.hidden = false;
  }

  /**
   * Update layout info from manual selection
   */
  updateLayoutInfoFromSelection(
    selectedType,
    layoutInfoGroup,
    layoutNameEl,
    layoutDescEl
  ) {
    let contentType, layout;

    // Handle specific news types
    if (selectedType === "news-simple") {
      contentType = "news";
      const newsLayouts = this.getLayoutVariations("news");
      // Directly use index 0 for "Berita Sederhana"
      layout = newsLayouts[0];
    } else if (selectedType === "news-newspaper") {
      contentType = "news";
      const newsLayouts = this.getLayoutVariations("news");
      // Directly use index 3 for "Berita Koran 2 Kolom"
      layout = newsLayouts[3];
    } else if (selectedType === "general") {
      contentType = "general";
      const layoutVariations = this.getLayoutVariations("general");
      layout =
        layoutVariations[Math.floor(Math.random() * layoutVariations.length)];
    } else {
      // Fallback to general for any unknown types
      contentType = "general";
      const layoutVariations = this.getLayoutVariations("general");
      layout = layoutVariations[0];
    }

    this.currentContentType = contentType;
    this.currentLayoutSelection = layout;

    layoutNameEl.textContent = layout.name;
    layoutDescEl.textContent = layout.description;
    layoutInfoGroup.hidden = false;
  }

