  /**
   * Get current text color from target element
   */
  getCurrentTextColor() {
    try {
      if (!this.targetElement) {
        return "#000000"; // Default black
      }

      // Get computed style of target element
      const computedStyle = window.getComputedStyle(this.targetElement);
      let color = computedStyle.color;

      // Convert RGB to HEX if needed
      if (color.startsWith("rgb")) {
        const rgbMatch = color.match(/\d+/g);
        if (rgbMatch && rgbMatch.length >= 3) {
          const r = parseInt(rgbMatch[0]);
          const g = parseInt(rgbMatch[1]);
          const b = parseInt(rgbMatch[2]);
          color =
            "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
        }
      }

      // If color is not valid, try parent elements
      if (!color || color === "rgb(0, 0, 0)" || color === "#000000") {
        let parent = this.targetElement.parentElement;
        while (
          parent &&
          (!color || color === "rgb(0, 0, 0)" || color === "#000000")
        ) {
          const parentStyle = window.getComputedStyle(parent);
          let parentColor = parentStyle.color;
          if (parentColor.startsWith("rgb")) {
            const rgbMatch = parentColor.match(/\d+/g);
            if (rgbMatch && rgbMatch.length >= 3) {
              const r = parseInt(rgbMatch[0]);
              const g = parseInt(rgbMatch[1]);
              const b = parseInt(rgbMatch[2]);
              parentColor =
                "#" +
                ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
            }
          }
          if (
            parentColor &&
            parentColor !== "rgb(0, 0, 0)" &&
            parentColor !== "#000000"
          ) {
            color = parentColor;
            break;
          }
          parent = parent.parentElement;
        }
      }

      // Ensure we have a valid color
      if (!color || color === "rgb(0, 0, 0)") {
        color = "#000000"; // Default black
      }

      // console.log("Text color detection:", {
      //   element: this.targetElement.tagName,
      //   computedColor: computedStyle.color,
      //   convertedColor: color,
      // });

      return color;
    } catch (error) {
      return "#000000"; // Default black
    }
  }

