  /**
   * Setup event listeners for font size dialog
   */
  setupFontSizeDialogEvents(container) {
    // Wait a bit for DOM to be ready
    setTimeout(() => {
      const slider = container.querySelector("#fontSizeSlider");
      const sizeDisplay = container.querySelector("#sizeDisplay");
      const textPreview = container.querySelector("#textPreview");
      const presetButtons = container.querySelectorAll(".size-preset");
      const cancelBtn = container.querySelector("#cancelFontSize");
      const applyBtn = container.querySelector("#applyFontSize");

      // Check if all required elements exist
      if (!slider || !sizeDisplay || !textPreview || !cancelBtn || !applyBtn) {
        return;
      }

      // Slider change handler
      slider.addEventListener("input", (e) => {
        const size = e.target.value;
        sizeDisplay.textContent = size;
        this.updateFontSizePreview(size);
        this.highlightActivePreset(presetButtons, size);
      });

      // Preset button handlers
      presetButtons.forEach((btn) => {
        btn.addEventListener("click", () => {
          const size = btn.dataset.size;
          slider.value = size;
          sizeDisplay.textContent = size;
          this.updateFontSizePreview(size);
          this.highlightActivePreset(presetButtons, size);
        });
      });

      // Apply button
      applyBtn.addEventListener("click", () => {
        const selectedSize = slider.value;
        this.applyFontSizeToSelection(selectedSize);
        window.closeModal("nexa-font-size-dialog");
        setTimeout(() => {
          container.remove();
        }, 300);
      });
    }, 100); // End of setTimeout
  }

  /**
   * Update font size preview
   */
  updateFontSizePreview(size) {
    const dialog = document.querySelector("#nexa-font-size-dialog");
    if (dialog) {
      const textPreview = dialog.querySelector("#textPreview");
      if (textPreview) {
        textPreview.style.fontSize = `${size}px`;
      }
    }
  }

  /**
   * Highlight active preset button
   */
  highlightActivePreset(buttons, activeSize) {
    buttons.forEach((btn) => {
      if (btn.dataset.size === activeSize) {
        btn.style.background = "#007bff";
        btn.style.color = "white";
      } else {
        btn.style.background = "white";
        btn.style.color = "black";
      }
    });
  }

