  /**
   * Generate images array for grid using lightweight approach
   */
  generateGridImages(config) {
    const { dimensions, imageSize, variableHeights } = config;
    const totalImages = dimensions.rows * dimensions.cols;
    const images = [];

    // Use demo Unsplash images for lightweight loading
    const unsplashImages = this.getGridUnsplashImages();

    for (let i = 0; i < totalImages; i++) {
      let height = imageSize.height;

      // Use variable heights for masonry layout
      if (variableHeights && i < variableHeights.length) {
        height = variableHeights[i];
      }

      // Use Unsplash images if available, otherwise fallback to lightweight placeholder
      const imageIndex = i % unsplashImages.length;
      const unsplashImg = unsplashImages[imageIndex];

      images.push({
        url: unsplashImg.thumb, // Use thumbnail for faster loading
        fullUrl: unsplashImg.url, // Full URL for click-to-view
        alt: `Photo by ${unsplashImg.photographer}`,
        width: imageSize.width,
        height: height || 200,
        photographer: unsplashImg.photographer,
      });
    }

    return images;
  }

