  /**
   * Create fallback SVG for grid images
   */
  createFallbackGridImage(width, height, number) {
    return `data:image/svg+xml;base64,${btoa(`
      <svg width="${width}" height="${height}" xmlns="http://www.w3.org/2000/svg">
        <rect width="${width}" height="${height}" fill="#e0e7ff"/>
        <text x="${width / 2}" y="${
      height / 2
    }" text-anchor="middle" fill="#4f46e5" font-family="Arial, sans-serif" font-size="16" font-weight="bold">${number}</text>
      </svg>
    `)}`;
  }

  /**
   * Add interactive effects to grid items
   */
  addGridInteractiveEffects(wrapper, img, gridType, config) {
    switch (gridType) {
      case "hover-zoom":
        wrapper.addEventListener("mouseenter", () => {
          img.style.transform = "scale(1.1)";
        });
        wrapper.addEventListener("mouseleave", () => {
          img.style.transform = "scale(1)";
        });
        break;

      case "overlay":
        const overlay = wrapper.querySelector(".nx-grid-overlay");
        if (overlay) {
          wrapper.addEventListener("mouseenter", () => {
            overlay.style.opacity = "1";
          });
          wrapper.addEventListener("mouseleave", () => {
            overlay.style.opacity = "0";
          });
        }
        break;

      case "portfolio":
        const portfolioOverlay = wrapper.querySelector(".nx-grid-overlay");
        if (portfolioOverlay) {
          wrapper.addEventListener("mouseenter", () => {
            portfolioOverlay.style.transform = "translateY(0)";
            img.style.transform = "scale(1.05)";
          });
          wrapper.addEventListener("mouseleave", () => {
            portfolioOverlay.style.transform = "translateY(100%)";
            img.style.transform = "scale(1)";
          });
        }
        break;

      case "photo-gallery":
      case "product-showcase":
        wrapper.addEventListener("mouseenter", () => {
          wrapper.style.transform = "translateY(-5px)";
          wrapper.style.boxShadow = "0 8px 25px rgba(0,0,0,0.15)";
        });
        wrapper.addEventListener("mouseleave", () => {
          wrapper.style.transform = "translateY(0)";
          wrapper.style.boxShadow = config.itemStyle.includes("box-shadow")
            ? config.itemStyle.match(/box-shadow: ([^;]+)/)[1]
            : "none";
        });
        break;

      case "lightbox":
        wrapper.addEventListener("mouseenter", () => {
          wrapper.style.boxShadow = "0 8px 20px rgba(0,0,0,0.2)";
          img.style.transform = "scale(1.05)";
        });
        wrapper.addEventListener("mouseleave", () => {
          wrapper.style.boxShadow = "none";
          img.style.transform = "scale(1)";
        });
        wrapper.addEventListener("click", () => {
          const fullUrl = img.dataset.fullUrl;
          if (fullUrl) {
            window.open(fullUrl, "_blank");
          } else {
          }
        });
        break;

      default:
        // Basic hover effect for all other grid types
        wrapper.addEventListener("mouseenter", () => {
          img.style.opacity = "0.9";
        });
        wrapper.addEventListener("mouseleave", () => {
          img.style.opacity = "1";
        });

        // Add click-to-view for all grids
        wrapper.addEventListener("click", () => {
          const fullUrl = img.dataset.fullUrl;
          if (fullUrl) {
            window.open(fullUrl, "_blank");
          }
        });
        break;
    }
  }

  /**
   * Context menu: Apply solid colors to background
   */
  contextBackgroundSolidColors() {
    try {
      if (!this.targetElement) {
        return { success: false, error: "No target element" };
      }

      this.createSolidColorDialog();
      return { success: true, message: "Solid color dialog opened" };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  /**
   * Context menu: Apply gradient backgrounds
   */
  contextBackgroundGradients() {
    try {
      if (!this.targetElement) {
        return { success: false, error: "No target element" };
      }

      this.createGradientDialog();
      return { success: true, message: "Gradient dialog opened" };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

