      this.gridSnapEnabled = !this.gridSnapEnabled;

      if (this.gridSnapEnabled) {
        // Grid snap is automatically applied to new elements
      } else {
      }

      return {
        success: true,
        message: `Grid snap ${this.gridSnapEnabled ? "enabled" : "disabled"}`,
      };
