  /**
   * Modal Element Creation Methods
   */

  /**
   * Inject Modal Control Functions to Global Scope
   */
  injectModalControlFunctions() {
    // Check if functions and listeners already exist to avoid duplication
    if (
      window.openModal &&
      window.closeModal &&
      window.nexaModalListenersAdded
    ) {
      return;
    }

    // Define global modal control functions
    window.openModal = function (modalId) {
      const modal = document.getElementById(modalId);
      if (modal) {
        modal.style.display = "block";
        modal.style.pointerEvents = "auto";
        setTimeout(() => {
          modal.classList.add("show");
        }, 10);
      }
    };

    window.closeModal = function (modalId) {
      const modal = document.getElementById(modalId);
      if (modal) {
        modal.classList.remove("show");
        setTimeout(() => {
          modal.style.display = "none";
          modal.style.pointerEvents = "none";

          // Restore context menu functionality after modal closes
          // This ensures context menu works properly after flowchart editor or other modals close
          if (
            window.nexaInteractInstance &&
            typeof window.nexaInteractInstance
              .ensureContextMenuFunctionality === "function"
          ) {
            window.nexaInteractInstance.ensureContextMenuFunctionality();

            // Additional check after a delay to ensure it took effect
            setTimeout(() => {
              const hasContextMenu =
                !!document.getElementById("nexa-context-menu");

              if (!hasContextMenu) {
                console.error(
                  "❌ Context menu still missing after restoration, forcing recreation"
                );
                window.nexaInteractInstance.createContextMenu();
              }
            }, 100);
          }
        }, 150);
      }
    };

    // Only add global event listeners once
    if (!window.nexaModalListenersAdded) {
      // Global event listeners for modal interactions
      // REMOVED: Click outside to close modal functionality
      // Modal can only be closed via close buttons or escape key

      document.addEventListener("keydown", function (e) {
        if (e.key === "Escape") {
          const openModals = document.querySelectorAll(".nx-modal.show");
          openModals.forEach((modal) => window.closeModal(modal.id));
        }
      });

      // Mark listeners as added to prevent duplication
      window.nexaModalListenersAdded = true;
    }
  }

